import React, { useState } from "react";
import "./Gallery.css";
import { toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

function Gallery({ cart, setCart }) {
  // --- Données artistes ---
  const artistsData = {
    Alice: {
      name: "Alice",
      img: "/img/alice.jpg",
      bio: "Alice est une peintre passionnée par les couleurs vives et les paysages oniriques.",
    },
    Bob: {
      name: "Bob",
      img: "/img/bob.jpg",
      bio: "Bob réalise des sculptures modernes, jouant avec la matière et les contrastes.",
    },
    Claire: {
      name: "Claire",
      img: "/img/claire.jpg",
      bio: "Claire aime le dessin minimaliste et explore les émotions par la simplicité des traits.",
    },
  };

  // --- Œuvres ---
  const artworks = [
    { id: 1, title: "Peinture 1", artist: "Alice", size: "50x70 cm", price: 120, img: "/img/art1.jpg" },
    { id: 2, title: "Sculpture 1", artist: "Bob", size: "30x40 cm", price: 200, img: "/img/art2.jpg" },
    { id: 3, title: "Dessin 1", artist: "Alice", size: "20x30 cm", price: 80, img: "/img/art3.jpg" },
    { id: 4, title: "Peinture 2", artist: "Claire", size: "60x80 cm", price: 150, img: "/img/art4.jpg" },
    { id: 5, title: "Sculpture 2", artist: "Bob", size: "45x60 cm", price: 180, img: "/img/art5.jpg" },
    { id: 6, title: "Dessin 2", artist: "Claire", size: "25x35 cm", price: 90, img: "/img/art6.jpg" },
  ];

  const [selectedArtist, setSelectedArtist] = useState("");

  // Filtrage des œuvres
  const filteredArtworks = artworks.filter(
    (art) => art.artist === selectedArtist
  );

  // Ajouter au panier
  const addToCart = (art) => {
    setCart([...cart, art]);
    toast.success(`${art.title} ajouté au panier !`, {
      position: "bottom-right",
      autoClose: 2000,
      style: {
        background: "#000",
        color: "#FFD700",
        border: "2px solid #FFD700",
        borderRadius: "8px",
        fontWeight: "bold",
      },
      progressStyle: { background: "#FFD700" },
      icon: false,
    });
  };

  return (
    <div className="gallery-container">
      <h2>Galerie d'art</h2>

      {/* --- Menu déroulant --- */}
      <div className="filter-bar">
        <select
          value={selectedArtist}
          onChange={(e) => setSelectedArtist(e.target.value)}
        >
          <option value="">Choisissez un artiste</option>
          {Object.keys(artistsData).map((artist) => (
            <option key={artist} value={artist}>
              {artist}
            </option>
          ))}
        </select>
      </div>

      {/* --- Infos artiste --- */}
      {selectedArtist && (
        <div className="artist-info">
          <img
            src={artistsData[selectedArtist].img}
            alt={artistsData[selectedArtist].name}
          />
          <p>{artistsData[selectedArtist].bio}</p>
        </div>
      )}

      {/* --- Œuvres --- */}
      {selectedArtist && (
        <div className="gallery-grid">
          {filteredArtworks.map((art) => (
            <div key={art.id} className="art-card">
              <img src={art.img} alt={art.title} />
              <h3>{art.title}</h3>
              <p className="size">{art.size}</p>
              <p className="price">{art.price} €</p>
              <button onClick={() => addToCart(art)}>Ajouter au panier</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Gallery;
